private boolean forbiddenURL(String full) {
    if (full.contains("@"))
        return true;
    if (full.startsWith("https://") == false && full.startsWith("http://") == false)
        return true;
    if (full.matches("^https?://[-#.0-9:\\[\\]+]+/.*"))  // <-- IPv6 覆盖不全
        return true;
    if (full.matches("^https?://[^.]+/.*"))
        return true;
    if (full.matches("^https?://[^.]+$"))
        return true;
    return false;
}

static SecurityProfile init() {
    final String env = SecurityUtils.getenv("PLANTUML_SECURITY_PROFILE");
    if ("SANDBOX".equalsIgnoreCase(env))
        return SANDBOX;
    else if ("ALLOWLIST".equalsIgnoreCase(env))
        return ALLOWLIST;
    else if ("INTERNET".equalsIgnoreCase(env))
        return INTERNET;
    else if ("UNSECURE".equalsIgnoreCase(env))
        return UNSECURE;
    return LEGACY;  // <-- 默认值，不校验任何 URL
}
